@page "/catalog"
@namespace sv_13418c2c80424c18ba622a940a444d8d.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* Left sidebar — filters *@
    <div class="col-lg-3 mb-3">
        <CatalogFilters Categories="_categories" OnFilterApplied="HandleFilterApplied" />
    </div>

    @* Main content area *@
    <div class="col-lg-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is not null && _result.Items.Count > 0)
        {
            <CatalogToolbar SortBy="@_sortBy"
                            Page="_page"
                            PageSize="PageSize"
                            TotalCount="_result.TotalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="_page"
                               PageSize="PageSize"
                               TotalCount="_result.TotalCount"
                               OnPageChanged="HandlePageChanged" />
        }
        else
        {
            <div class="text-center py-5 text-muted">
                <h5>No products found</h5>
                <p>Try adjusting your filters.</p>
            </div>
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    /// <summary>Raised when a product card is clicked (not Add to Cart).</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            await Task.WhenAll(categoriesTask, searchTask);

            _categories = categoriesTask.Result;
            _result = searchTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire up cart service here
        return Task.CompletedTask;
    }
}

